func serviceLabel(ctx context.Context, service string) string {
	switch strings.ToLower(service) {
	case "github":
		return i18n.T(ctx, "ViewOnGitHub") + " ↗"
	case "gitlab":
		return i18n.T(ctx, "ViewOnGitLab") + " ↗"
	default:
		return i18n.T(ctx, "ViewOnService") + " ↗"
	}
}

