func l1RescanTitle(ctx context.Context, reason string) string {
	switch reason {
	case "private":
		return i18n.T(ctx, "projects.RescanL1DisabledPrivate")
	case "no_token":
		return i18n.T(ctx, "projects.RescanL1DisabledNoToken")
	default:
		return ""
	}
}

// githubRepoPath returns "owner/repo" for GitHub URLs, or the cleaned path for other hosts.
func githubRepoPath(url string) string {
	u := strings.TrimSpace(url)
	u = strings.TrimPrefix(u, "https://github.com/")
	u = strings.TrimPrefix(u, "http://github.com/")
	u = strings.TrimSuffix(u, "/")
	u = strings.TrimSuffix(u, ".git")
	if u == "" {
		return url
	}
	return u
}

